    interior_coord = None
    for r in range(1, height + 1):
        if interior_coord is not None:
            break
        for c in range(1, width + 1):
            tile = Tile(r, c)
            if tile.color == 'red':
                continue
            red_neighbors = 0
            for rt in red_tiles:
                if g.hex_distance(rt, (r, c)) == 1:
                    red_neighbors += 1
            if red_neighbors == 6:
                interior_coord = (r, c)
                break

    if interior_coord is not None:
        interior_tile = Tile(*interior_coord).draw('red')

    interior_row, interior_col = interior_coord

    def left_filter(row, col):
        return col < interior_col

    def upper_right_filter(row, col):
        return row <= interior_row and col >= interior_col - 1

    def lower_right_filter(row, col):
        return row >= interior_row and col >= interior_col

    def find_border_row(start_coord, end_coord, side_tiles, region_filter):
        candidates = []
        for rr in range(1, height + 1):
            for cc in range(1, width + 1):
                if (rr, cc) == interior_coord:
                    continue
                if not region_filter(rr, cc):
                    continue
                tile = Tile(rr, cc)
                if tile.color != 'white':
                    continue
                for s in side_tiles:
                    if g.hex_distance(s, (rr, cc)) == 1:
                        path_len = g.hex_distance(start_coord, (rr, cc)) + g.hex_distance((rr, cc), end_coord)
                        candidates.append(((rr, cc), path_len))
                        break
        candidates.sort(key=lambda item: (item[1], item[0][0], item[0][1]))
        return [coord for coord, _ in candidates[:5]]

    upper_right_border_coords = find_border_row(top_left_coord, right_coord, upper_right_side, upper_right_filter)
    green_border_tiles = [Tile(r, c).draw('green') for (r, c) in upper_right_border_coords]

    lower_right_border_coords = find_border_row(bottom_left_coord, right_coord, lower_right_side, lower_right_filter)
    blue_border_tiles = [Tile(r, c).draw('blue') for (r, c) in lower_right_border_coords]

    left_border_coords = find_border_row(top_left_coord, bottom_left_coord, left_side, left_filter)
    orange_border_tiles = [Tile(r, c).draw('orange') for (r, c) in left_border_coords]

    orange_apex_coord = (height - 4, 1)
