    green_apex = Tile(*green_apex_coord).draw('green')

    blue_apex_coord = (height, 10)
    blue_apex = Tile(*blue_apex_coord).draw('blue')

    def hex_to_point(coord):
        row, col = coord
        col_parity = col & 1
        z = row - (col - col_parity) // 2
        x = col
        X = x + z / 2.0
        Y = float(z)
        return (X, Y)

    def point_in_triangle(p, a, b, c):
        def sign(p1, p2, p3):
            return (p1[0] - p3[0]) * (p2[1] - p3[1]) - (p2[0] - p3[0]) * (p1[1] - p3[1])
        d1 = sign(p, a, b)
        d2 = sign(p, b, c)
        d3 = sign(p, c, a)
        has_neg = (d1 < 0) or (d2 < 0) or (d3 < 0)
        has_pos = (d1 > 0) or (d2 > 0) or (d3 > 0)
        return not (has_neg and has_pos)

    def get_row_endpoints(row_coords):
        if not row_coords:
            return None, None
        end1 = row_coords[0]
        end2 = row_coords[0]
        max_dist = -1
        for i in range(len(row_coords)):
            for j in range(i + 1, len(row_coords)):
                d = g.hex_distance(row_coords[i], row_coords[j])
                if d > max_dist:
                    max_dist = d
                    end1 = row_coords[i]
                    end2 = row_coords[j]
        return end1, end2

    def build_and_fill_triangle(color, row_coords, apex_coord):
        if not row_coords:
            return
        end1, end2 = get_row_endpoints(row_coords)
        if end1 is None or end2 is None:
            return
        for rr, cc in row_coords:
            Tile(rr, cc).draw(color)
        for endpoint in (end1, end2):
            for t in g.hex_line(endpoint, apex_coord):
                if t.color in ('white', color):
                    t.draw(color)
        a_pt = hex_to_point(apex_coord)
        b_pt = hex_to_point(end1)
        c_pt = hex_to_point(end2)
        for rr in range(1, height + 1):
            for cc in range(1, width + 1):
                if (rr, cc) == interior_coord:
                    continue
                p_pt = hex_to_point((rr, cc))
                if not point_in_triangle(p_pt, a_pt, b_pt, c_pt):
                    continue
                tile = Tile(rr, cc)
                if tile.color in ('white', color):
                    tile.draw(color)

    build_and_fill_triangle('green', upper_right_border_coords, green_apex_coord)
    build_and_fill_triangle('blue', lower_right_border_coords, blue_apex_coord)
    build_and_fill_triangle('orange', left_border_coords, orange_apex_coord)

    board_state = g.board_state
